            if (lrk == 1 && rrk == 1) {
                int lsz = arr_size(lv);
                int rsz = arr_size(rv);
                if (lsz != rsz) { eval_err = 3; return -1; }
                int r = arr_vector(lsz);
                if (r < 0) { eval_err = 5; return -1; }
                int i = 0;
                while (i < lsz) {
                    arr_set(r, i, eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i)));
